import React, { useRef, useState, useEffect } from "react";
import AboutPanel from "./AboutPanel";
import ContactPanel from "./ContactPanel";

function useClickOutside(ref, callback) {
  useEffect(() => {
    const handle = (e) => {
      if (ref.current && !ref.current.contains(e.target)) callback();
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [ref, callback]);
}

export default function Infopanels() {
  const [openPanel, setOpenPanel] = useState(null); // "left" | "right" | null
  const [hoveredPanel, setHoveredPanel] = useState(null);
  const panelsRef = useRef(null);

  useClickOutside(panelsRef, () => setOpenPanel(null));

  return (
    <div
      id="info-panels"
      ref={panelsRef}
      style={{
        background: "rgb(79, 103, 125)",
        padding: "24px 20px 28px",
        marginTop: "20px",
        marginBottom: "0",
      }}
    >
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "30px",
          alignItems: "flex-start",
          justifyContent: "center",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {/* PANEL IZQUIERDO: Presentación */}
        <AboutPanel
          isOpen={openPanel === "left"}
          onToggle={() =>
            setOpenPanel(openPanel === "left" ? null : "left")
          }
          hovered={hoveredPanel}
          onHover={setHoveredPanel}
          onLeave={() => setHoveredPanel(null)}
        />

        {/* PANEL DERECHO: Contacto */}
        <ContactPanel
          isOpen={openPanel === "right"}
          onToggle={() =>
            setOpenPanel(openPanel === "right" ? null : "right")
          }
          hovered={hoveredPanel}
          onHover={setHoveredPanel}
          onLeave={() => setHoveredPanel(null)}
        />
      </div>
    </div>
  );
}
